suggested_fix:
Replace `this.set(setting)` with `this.get(setting)` in both methods:

```javascript
app.enabled = function enabled(setting) {
  return Boolean(this.get(setting));
};

app.disabled = function disabled(setting) {
  return !this.get(setting);
};
```

Add validation for the `ext` parameter to ensure it's a non-empty string:

```javascript
if (typeof ext !== 'string' || ext.length === 0) {
  throw new TypeError('extension must be a non-empty string');
}
```

Refactor the entire codebase to use `const` for constants and `let` for block-scoped variables. For example:

```javascript
// Instead of:
var app = function(req, res, next) { ... };
var methods = require('./utils').methods;
var slice = Array.prototype.slice;

// Use:
const app = function(req, res, next) { ... };
const methods = require('./utils').methods;
const slice = Array.prototype.slice;
```
